function report = runWorkingPrecisionValidation(options)
%RUNWORKINGPRECISIONVALIDATION Compare CPU-single with CPU-double.
%
% Camera geometry and height labels remain double. Prepared intensity,
% dense ZNCC moments/costs, and SGM recurrence arrays use the selected
% working precision. Every reported scene is evaluated over its complete
% image rather than a pixel subset.
%
% Traceability: algo/main.tex Secs. 5.4, 5.6, and 14.6; Eqs. (68)--(75);
% implementation plan Stage C3.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [96, 112]
    options.TextureSeeds (1, :) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = [71, 73, 79]
    options.HeightRangeMetres (1, 2) double ...
        {mustBeFinite, mustBeIncreasing} = [-50, 50]
    options.LabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeGreaterThanOrEqual( ...
        options.LabelCount, 3)} = 33
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [48, 56]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.SgmImplementation (1, 1) string ...
        {mustBeMember(options.SgmImplementation, ...
        ["reference", "vectorized"])} = "vectorized"
    options.StableMargin (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 1e-4
    options.MaximumMedianEndpointDeltaPixels (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.01
    options.MaximumP99EndpointDeltaPixels (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.05
    options.OutputFile (1, 1) string = ""
end

z = linspace(options.HeightRangeMetres(1), ...
    options.HeightRangeMetres(2), options.LabelCount);
n = numel(options.TextureSeeds);
doubleZnccSeconds = zeros(n, 1);
singleZnccSeconds = zeros(n, 1);
doubleSgmSeconds = zeros(n, 1);
singleSgmSeconds = zeros(n, 1);
maximumCostDelta = zeros(n, 1);
finiteMaskEqual = false(n, 1);
rawPass = false(n, 1);
rawStableDisagreements = zeros(n, 1);
rawLowerMarginDisagreements = zeros(n, 1);
rawMedianEndpointDelta = zeros(n, 1);
rawP99EndpointDelta = zeros(n, 1);
sgmPass = false(n, 1);
sgmStableDisagreements = zeros(n, 1);
sgmLowerMarginDisagreements = zeros(n, 1);
sgmMedianEndpointDelta = zeros(n, 1);
sgmP99EndpointDelta = zeros(n, 1);
doubleFeatureBytes = zeros(n, 1);
singleFeatureBytes = zeros(n, 1);
doubleOutputBytes = zeros(n, 1);
singleOutputBytes = zeros(n, 1);
details = repmat(struct("Raw", struct, "Sgm", struct), n, 1);
products = ["LabelIndex", "BestCost", "Margin", "Correspondence"];

for k = 1:n
    renderer = SyntheticPinholeRenderer( ...
        "working-precision-" + string(options.TextureSeeds(k)), ...
        options.ImageSize, Supersample=2, PsfSigmaPixels=0.5, ...
        TextureSeed=options.TextureSeeds(k));
    pair = renderer.renderPair;
    g = HeightSweepGeometry( ...
        renderer.ReferenceCamera, renderer.MovingCamera);
    levels = 2 ^ renderer.BitDepth - 1;
    r64 = double(pair.ReferenceImage) ./ levels;
    m64 = double(pair.MovingImage) ./ levels;
    r32 = single(pair.ReferenceImage) ./ single(levels);
    m32 = single(pair.MovingImage) ./ single(levels);
    c64 = HeightCostCurve(g, r64, m64, ...
        DerivativeSigma=1, IntegrationSigma=1, ...
        ReferenceValid=pair.ReferenceValid, ...
        MovingValid=pair.MovingValid, PrepareGradients=false, ...
        WorkingPrecision="double");
    c32 = HeightCostCurve(g, r32, m32, ...
        DerivativeSigma=1, IntegrationSigma=1, ...
        ReferenceValid=pair.ReferenceValid, ...
        MovingValid=pair.MovingValid, PrepareGradients=false, ...
        WorkingPrecision="single");
    d64 = DenseHeightSweep(c64);
    d32 = DenseHeightSweep(c32);
    q64 = d64.runZnccOptimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=true, UseParallel=false, ...
        WorkingPrecision="double", Products=products);
    q32 = d32.runZnccOptimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=true, UseParallel=false, ...
        WorkingPrecision="single", Products=products);
    raw = HeightSweepEquivalence.comparePrecision(q64, q32, ...
        StableMargin=options.StableMargin, ...
        MaximumMedianEndpointDeltaPixels= ...
        options.MaximumMedianEndpointDeltaPixels, ...
        MaximumP99EndpointDeltaPixels= ...
        options.MaximumP99EndpointDeltaPixels);

    jointlyFinite = isfinite(q64.CostVolume) ...
        & isfinite(q32.CostVolume);
    delta = abs(double(q64.CostVolume(jointlyFinite)) ...
        - double(q32.CostVolume(jointlyFinite)));
    if isempty(delta)
        maximumCostDelta(k) = 0;
    else
        maximumCostDelta(k) = max(delta);
    end
    finiteMaskEqual(k) = isequal( ...
        isfinite(q64.CostVolume), isfinite(q32.CostVolume));

    if options.SgmImplementation == "vectorized"
        s64 = HeightSgm.aggregateVectorized(q64.CostVolume, z, ...
            DirectionCount=options.DirectionCount);
        s32 = HeightSgm.aggregateVectorized(q32.CostVolume, z, ...
            DirectionCount=options.DirectionCount);
    else
        s64 = HeightSgm.aggregate(q64.CostVolume, z, ...
            DirectionCount=options.DirectionCount);
        s32 = HeightSgm.aggregate(q32.CostVolume, z, ...
            DirectionCount=options.DirectionCount);
    end
    p64 = d64.projectHeightMap(s64.HeightMetres, s64.Valid);
    p32 = d32.projectHeightMap(s32.HeightMetres, s32.Valid);
    a64 = selectionResult(s64, p64);
    a32 = selectionResult(s32, p32);
    regularized = HeightSweepEquivalence.comparePrecision(a64, a32, ...
        StableMargin=options.StableMargin, ...
        MaximumMedianEndpointDeltaPixels= ...
        options.MaximumMedianEndpointDeltaPixels, ...
        MaximumP99EndpointDeltaPixels= ...
        options.MaximumP99EndpointDeltaPixels);

    doubleZnccSeconds(k) = q64.Runtime.EvaluationSeconds;
    singleZnccSeconds(k) = q32.Runtime.EvaluationSeconds;
    doubleSgmSeconds(k) = s64.RuntimeSeconds;
    singleSgmSeconds(k) = s32.RuntimeSeconds;
    rawPass(k) = raw.Pass;
    rawStableDisagreements(k) = raw.StableLabelDisagreementCount;
    rawLowerMarginDisagreements(k) = ...
        raw.LowerMarginLabelDisagreementCount;
    rawMedianEndpointDelta(k) = raw.MedianEndpointDeltaPixels;
    rawP99EndpointDelta(k) = raw.P99EndpointDeltaPixels;
    sgmPass(k) = regularized.Pass;
    sgmStableDisagreements(k) = ...
        regularized.StableLabelDisagreementCount;
    sgmLowerMarginDisagreements(k) = ...
        regularized.LowerMarginLabelDisagreementCount;
    sgmMedianEndpointDelta(k) = ...
        regularized.MedianEndpointDeltaPixels;
    sgmP99EndpointDelta(k) = regularized.P99EndpointDeltaPixels;
    doubleFeatureBytes(k) = featurePayloadBytes(c64.Reference) ...
        + featurePayloadBytes(c64.Moving);
    singleFeatureBytes(k) = featurePayloadBytes(c32.Reference) ...
        + featurePayloadBytes(c32.Moving);
    doubleOutputBytes(k) = q64.Runtime.OutputArrayBytes;
    singleOutputBytes(k) = q32.Runtime.OutputArrayBytes;
    details(k).Raw = raw;
    details(k).Sgm = regularized;
end

seed = reshape(options.TextureSeeds, [], 1);
znccSpeedup = doubleZnccSeconds ./ singleZnccSeconds;
sgmSpeedup = doubleSgmSeconds ./ singleSgmSeconds;
results = table(seed, doubleZnccSeconds, singleZnccSeconds, znccSpeedup, ...
    doubleSgmSeconds, singleSgmSeconds, sgmSpeedup, ...
    maximumCostDelta, finiteMaskEqual, rawPass, ...
    rawStableDisagreements, rawLowerMarginDisagreements, ...
    rawMedianEndpointDelta, rawP99EndpointDelta, sgmPass, ...
    sgmStableDisagreements, sgmLowerMarginDisagreements, ...
    sgmMedianEndpointDelta, sgmP99EndpointDelta, ...
    doubleFeatureBytes, singleFeatureBytes, ...
    doubleOutputBytes, singleOutputBytes, ...
    VariableNames=["TextureSeed", "DoubleZnccSeconds", ...
    "SingleZnccSeconds", "ZnccSpeedup", "DoubleSgmSeconds", ...
    "SingleSgmSeconds", "SgmSpeedup", "MaximumCostDelta", ...
    "FiniteCostMaskEqual", "RawPass", "RawStableDisagreements", ...
    "RawLowerMarginDisagreements", "RawMedianEndpointDeltaPixels", ...
    "RawP99EndpointDeltaPixels", "SgmPass", ...
    "SgmStableDisagreements", "SgmLowerMarginDisagreements", ...
    "SgmMedianEndpointDeltaPixels", "SgmP99EndpointDeltaPixels", ...
    "DoubleFeatureBytes", "SingleFeatureBytes", ...
    "DoubleOutputBytes", "SingleOutputBytes"]);
policy = struct( ...
    "StableMargin", options.StableMargin, ...
    "MaximumMedianEndpointDeltaPixels", ...
    options.MaximumMedianEndpointDeltaPixels, ...
    "MaximumP99EndpointDeltaPixels", ...
    options.MaximumP99EndpointDeltaPixels, ...
    "MaskPolicy", "exact finite cost and final-valid masks", ...
    "StableLabelPolicy", ...
    "exact labels where CPU-double margin exceeds StableMargin");
report = struct( ...
    "Policy", policy, ...
    "Results", results, ...
    "Details", details, ...
    "AllPass", all(finiteMaskEqual & rawPass & sgmPass), ...
    "ImageSize", options.ImageSize, ...
    "HeightLabelsMetres", z, ...
    "DirectionCount", options.DirectionCount, ...
    "SgmImplementation", options.SgmImplementation, ...
    "GeometryPrecision", "double", ...
    "WorkingPrecisions", ["double", "single"], ...
    "ArrayLayout", "[row,column,label]", ...
    "InvalidCost", "NaN", ...
    "PixelConvention", ...
    "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0");

disp(results);
fprintf("Working-precision validation pass: %s\n", string(report.AllPass));
if options.OutputFile ~= ""
    save(options.OutputFile, "report", "-v7.3");
end
end

function result = selectionResult(sgm, projection)
result = struct( ...
    "HeightMetres", projection.HeightMetres, ...
    "CorrespondenceXY", projection.CorrespondenceXY, ...
    "Valid", projection.Valid, ...
    "LabelIndex", sgm.LabelIndex, ...
    "CostMargin", sgm.CostMargin);
end

function bytes = featurePayloadBytes(feature)
names = properties(feature);
bytes = 0;
for k = 1:numel(names)
    value = feature.(names{k}); %#ok<NASGU>
    info = whos("value");
    bytes = bytes + info.bytes;
end
end

function mustBeIncreasing(x)
if x(2) <= x(1)
    error("runWorkingPrecisionValidation:HeightRangeNotIncreasing", ...
        "HeightRangeMetres must be strictly increasing.");
end
end
